-- File: data_f16_bird_transfers.sql
-- Flock 16 bird transfers (Kpally -> Potlapally)

CREATE TABLE IF NOT EXISTS public.bird_transfers (
  id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,
  flock_id UUID REFERENCES public.flocks(id),
  transfer_date DATE NOT NULL,
  dc_no TEXT,
  grade TEXT,
  gender TEXT CHECK (gender IN ('female','male')),
  vehicle_no TEXT,
  no_of_boxes INTEGER,
  birds_per_box INTEGER,
  total_birds INTEGER NOT NULL,
  from_farm_id UUID REFERENCES public.farms(id),
  to_farm_id UUID REFERENCES public.farms(id),
  remarks TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);
ALTER TABLE public.bird_transfers ENABLE ROW LEVEL SECURITY;
CREATE POLICY IF NOT EXISTS "auth_select" ON public.bird_transfers FOR SELECT USING (auth.role()='authenticated');
CREATE POLICY IF NOT EXISTS "auth_insert" ON public.bird_transfers FOR INSERT WITH CHECK (auth.role()='authenticated');
CREATE POLICY IF NOT EXISTS "auth_update" ON public.bird_transfers FOR UPDATE USING (auth.role()='authenticated');
CREATE POLICY IF NOT EXISTS "auth_delete" ON public.bird_transfers FOR DELETE USING (auth.role()='authenticated');

